{"children":[],"lineage":["dir:crates/orbit-engine/src/activity_job","file:crates/orbit-engine/src/activity_job/job_executor.rs"],"lines":[59,110],"selector":"symbol:crates/orbit-engine/src/activity_job/job_executor.rs#execute_job:function","siblings":["symbol:crates/orbit-engine/src/activity_job/job_executor.rs#DEFAULT_MODEL_FOR_SESSION:field","symbol:crates/orbit-engine/src/activity_job/job_executor.rs#JobOutcome:struct","symbol:crates/orbit-engine/src/activity_job/job_executor.rs#ExecCtx:struct"],"source":"pub fn execute_job(
    job: &JobV2,
    input: Value,
    run_id: &str,
    audit: Arc<V2AuditWriter>,
    host: &dyn V2RuntimeHost,
) -> Result<JobOutcome, DispatchError> {
    validate_job(job)?;

    let base_input = merge_job_input(job.default_input.as_ref(), &input);

    let ctx = ExecCtx {
        run_id: run_id.to_string(),
        audit: audit.clone(),
        host,
        input: base_input.clone(),
        pipeline: Arc::new(Mutex::new(HashMap::new())),
        sessions: Arc::new(Mutex::new(HashMap::new())),
        item: None,
        iteration: None,
    };

    let mut overall_ok = true;
    let mut overall_message = None;
    for step in &job.steps {
        let outcome = run_step(step, &ctx)?;
        if !outcome.success {
            overall_ok = false;
            overall_message = Some(
                outcome
                    .message
                    .unwrap_or_else(|| format!("step `{}` completed with success=false", step.id)),
            );
            break;
        }
    }

    let pipeline = Value::Object(
        ctx.pipeline
            .lock()
            .expect("pipeline poisoned")
            .clone()
            .into_iter()
            .collect(),
    );

    Ok(JobOutcome {
        success: overall_ok,
        pipeline,
        message: (!overall_ok).then_some(overall_message).flatten(),
    })
}"}

